/**
 * Audio-Reactor
 * Hooks into the global APlayer instance, extracts audio frequency data using Web Audio API,
 * and updates CSS variables to enable Audio-Reactive UI across the blog.
 * Features a fallback to "Synthetic Beat" if CORS restricts audio data extraction.
 */
(function() {
  'use strict';

  if (window.AudioReactor) return;

  const AudioReactor = {
    audioEl: null,
    ctx: null,
    analyser: null,
    freqData: null,
    source: null,

    // Extracted data
    data: {
      bass: 0,
      mid: 0,
      treble: 0,
      energy: 0,
      isPlaying: false
    },

    // Status
    isInitialized: false,
    useSynthetic: false,
    silentFrames: 0,
    subscribers: [],

    // Subscribe to real-time data
    subscribe: function(callback) {
      if (typeof callback === 'function') {
        this.subscribers.push(callback);
      }
    },

    unsubscribe: function(callback) {
      this.subscribers = this.subscribers.filter(cb => cb !== callback);
    },

    init: function() {
      // Find the APlayer audio element
      const audioEls = document.querySelectorAll('audio');
      let targetAudio = null;

      // Prefer the one inside aplayer
      for (let i = 0; i < audioEls.length; i++) {
        if (audioEls[i].closest('.aplayer')) {
          targetAudio = audioEls[i];
          break;
        }
      }

      if (!targetAudio && audioEls.length > 0) {
        targetAudio = audioEls[0];
      }

      if (!targetAudio) return;

      this.audioEl = targetAudio;

      // We must initialize AudioContext after a user gesture.
      // APlayer's play event is a good time.
      this.audioEl.addEventListener('play', () => {
        this.data.isPlaying = true;
        this.setupAudioGraph();
        this.startLoop();
      });

      this.audioEl.addEventListener('pause', () => {
        this.data.isPlaying = false;
        this.resetCSSVars();
      });

      this.audioEl.addEventListener('ended', () => {
        this.data.isPlaying = false;
        this.resetCSSVars();
      });

      // If already playing when script loads (unlikely but possible)
      if (!this.audioEl.paused) {
        this.data.isPlaying = true;
        this.setupAudioGraph();
        this.startLoop();
      }
    },

    setupAudioGraph: function() {
      if (this.isInitialized) {
        if (this.ctx && this.ctx.state === 'suspended') {
          this.ctx.resume().catch(console.error);
        }
        return;
      }

      try {
        const AudioContext = window.AudioContext || window.webkitAudioContext;
        if (!AudioContext) {
          this.useSynthetic = true;
          this.isInitialized = true;
          return;
        }

        // Share context with music-universe if it exists to prevent double-hooking issues
        if (window.__msAudioGraph && window.__msAudioGraph.ctx) {
          this.ctx = window.__msAudioGraph.ctx;
          this.analyser = window.__msAudioGraph.analyser;
          this.freqData = window.__msAudioGraph.freq;
          this.isInitialized = true;
          return;
        }

        this.ctx = new AudioContext();
        this.analyser = this.ctx.createAnalyser();
        this.analyser.fftSize = 256;
        this.analyser.smoothingTimeConstant = 0.82;
        this.freqData = new Uint8Array(this.analyser.frequencyBinCount);

        // Try setting crossorigin to anonymous to allow CORS
        try { this.audioEl.crossOrigin = 'anonymous'; } catch(e) {}

        this.source = this.ctx.createMediaElementSource(this.audioEl);
        this.source.connect(this.analyser);
        this.analyser.connect(this.ctx.destination);

        this.isInitialized = true;
      } catch (e) {
        console.warn('AudioReactor: AudioContext creation failed, using synthetic beat', e);
        this.useSynthetic = true;
        this.isInitialized = true;
      }
    },

    updateData: function() {
      if (!this.data.isPlaying) return;

      let b = 0, m = 0, t = 0, e = 0;
      const now = performance.now() / 1000;

      if (this.analyser && this.freqData && !this.useSynthetic) {
        this.analyser.getByteFrequencyData(this.freqData);

        let sum = 0;
        let bc = 0, mc = 0, tc = 0;
        const n = this.freqData.length;

        for (let i = 0; i < n; i++) {
          const val = this.freqData[i] / 255;
          sum += this.freqData[i];

          if (i < n * 0.12) { b += val; bc++; }
          else if (i < n * 0.5) { m += val; mc++; }
          else { t += val; tc++; }
        }

        b = bc ? b / bc : 0;
        m = mc ? m / mc : 0;
        t = tc ? t / tc : 0;
        e = sum / (n * 255);

        if (sum < 2) {
          this.silentFrames++;
        } else {
          this.silentFrames = 0;
        }

        // If playing but no data for a while, assume CORS restriction
        if (this.silentFrames > 90) {
          this.useSynthetic = true;
        }
      }

      if (this.useSynthetic || (!this.analyser)) {
        b = 0.35 + 0.3 * (0.5 + 0.5 * Math.sin(now * 3.1));
        m = 0.3 + 0.25 * (0.5 + 0.5 * Math.sin(now * 1.7 + 1.0));
        t = 0.2 + 0.2 * (0.5 + 0.5 * Math.sin(now * 6.3 + 2.0));
        e = (b + m + t) / 3;
      }

      // Smooth updates
      this.data.bass = this.lerp(this.data.bass, b, 0.2);
      this.data.mid = this.lerp(this.data.mid, m, 0.2);
      this.data.treble = this.lerp(this.data.treble, t, 0.2);
      this.data.energy = this.lerp(this.data.energy, e, 0.2);
    },

    updateCSS: function() {
      // Throttle CSS updates slightly or directly apply
      const root = document.documentElement;
      // Use toFixed to prevent massive string generation and layout trashing
      root.style.setProperty('--music-bass', this.data.bass.toFixed(3));
      root.style.setProperty('--music-mid', this.data.mid.toFixed(3));
      root.style.setProperty('--music-treble', this.data.treble.toFixed(3));
      root.style.setProperty('--music-energy', this.data.energy.toFixed(3));
    },

    resetCSSVars: function() {
      const root = document.documentElement;
      root.style.setProperty('--music-bass', '0');
      root.style.setProperty('--music-mid', '0');
      root.style.setProperty('--music-treble', '0');
      root.style.setProperty('--music-energy', '0');
      this.data.bass = 0;
      this.data.mid = 0;
      this.data.treble = 0;
      this.data.energy = 0;
    },

    startLoop: function() {
      const loop = () => {
        if (!this.data.isPlaying) return;

        // Pause processing if page is hidden to save battery
        if (document.visibilityState === 'visible') {
          this.updateData();
          this.updateCSS();

          for (let i = 0; i < this.subscribers.length; i++) {
            this.subscribers[i](this.data);
          }
        }

        requestAnimationFrame(loop);
      };

      requestAnimationFrame(loop);
    },

    lerp: function(start, end, amt) {
      return (1 - amt) * start + amt * end;
    }
  };

  window.AudioReactor = AudioReactor;

  // Wait for APlayer / MetingJS to inject the audio element
  const observer = new MutationObserver((mutations) => {
    if (document.querySelector('audio')) {
      AudioReactor.init();
      observer.disconnect();
    }
  });

  if (document.querySelector('audio')) {
    AudioReactor.init();
  } else {
    observer.observe(document.body, { childList: true, subtree: true });
  }

})();

/* ============================================
 * 心灵感应环境音合成器 (Telepathic Ambient Synth)
 * 纯代码实时生成的宇宙深空低频环境音效
 * ============================================ */

(() => {
  'use strict';

  class AmbientSynth {
    constructor() {
      this.audioCtx = null;
      this.osc1 = null;
      this.osc2 = null;
      this.filter = null;
      this.gainNode = null;
      this.isPlaying = false;
      this.baseFreq1 = 55; // A1
      this.baseFreq2 = 110; // A2

      this.scrollTarget = 0;
      this.currentScroll = 0;

      // Bindings
      this.handleScroll = this.handleScroll.bind(this);
      this.handleMouseMove = this.handleMouseMove.bind(this);
      this.updateLoop = this.updateLoop.bind(this);
    }

    init() {
      if (this.audioCtx) return;
      const AudioContext = window.AudioContext || window.webkitAudioContext;
      if (!AudioContext) return;

      this.audioCtx = new AudioContext();

      // Master Gain
      this.gainNode = this.audioCtx.createGain();
      this.gainNode.gain.value = 0;
      this.gainNode.connect(this.audioCtx.destination);

      // Lowpass Filter
      this.filter = this.audioCtx.createBiquadFilter();
      this.filter.type = 'lowpass';
      this.filter.frequency.value = 400;
      this.filter.Q.value = 5;
      this.filter.connect(this.gainNode);

      // Oscillator 1 (Sub)
      this.osc1 = this.audioCtx.createOscillator();
      this.osc1.type = 'sine';
      this.osc1.frequency.value = this.baseFreq1;
      this.osc1.connect(this.filter);

      // Oscillator 2 (Drone)
      this.osc2 = this.audioCtx.createOscillator();
      this.osc2.type = 'triangle';
      this.osc2.frequency.value = this.baseFreq2;

      // Panner for Osc 2
      this.panner = this.audioCtx.createStereoPanner ? this.audioCtx.createStereoPanner() : this.audioCtx.createGain();
      this.osc2.connect(this.panner);
      this.panner.connect(this.filter);

      this.osc1.start();
      this.osc2.start();

      window.addEventListener('scroll', this.handleScroll, { passive: true });
      window.addEventListener('mousemove', this.handleMouseMove, { passive: true });
      requestAnimationFrame(this.updateLoop);
    }

    start() {
      this.init();
      if (this.audioCtx.state === 'suspended') this.audioCtx.resume();
      this.gainNode.gain.setTargetAtTime(0.3, this.audioCtx.currentTime, 2);
      this.isPlaying = true;
    }

    stop() {
      if (!this.isPlaying) return;
      this.gainNode.gain.setTargetAtTime(0.001, this.audioCtx.currentTime, 1);
      setTimeout(() => {
        if (this.audioCtx && this.audioCtx.state === 'running') {
          this.audioCtx.suspend();
        }
        this.isPlaying = false;
      }, 2000);
    }

    handleScroll() {
      this.scrollTarget = 1;
    }

    handleMouseMove(e) {
      if (!this.isPlaying || !this.audioCtx) return;
      const x = e.clientX / window.innerWidth;
      const y = e.clientY / window.innerHeight;

      if (this.panner.pan) {
        this.panner.pan.setTargetAtTime((x * 2) - 1, this.audioCtx.currentTime, 0.1);
      }

      const newFreq = this.baseFreq2 + (1 - y) * 20;
      this.osc2.frequency.setTargetAtTime(newFreq, this.audioCtx.currentTime, 0.5);
    }

    updateLoop() {
      if (this.isPlaying && this.audioCtx) {
        // Decay scroll target
        this.scrollTarget *= 0.95;
        this.currentScroll += (this.scrollTarget - this.currentScroll) * 0.1;

        // Modulate filter based on scroll
        const minCutoff = 200;
        const maxCutoff = 1500;
        const cutoff = minCutoff + (maxCutoff - minCutoff) * this.currentScroll;
        this.filter.frequency.setTargetAtTime(cutoff, this.audioCtx.currentTime, 0.1);
      }
      requestAnimationFrame(this.updateLoop);
    }
  }

  window.AmbientSynth = new AmbientSynth();
})();

/* ============================================
 * 加密增强系统 🎭
 *
 * 功能集成：
 *   #1 解密彩蛋 — 输错密码显示假文章
 *   #2 密码线索迷宫 — 需要先在别的文章找到线索
 *   #3 成就系统 — 累积解密次数获得称号
 *   #4 解密烟花 — 成功解密触发庆祝
 *   #5 阅后即焚 — 解密后离开页面自动重新加密
 *   #6 知识问答解锁 — 答对问题才显示密码框
 *   #7 双人解密 — 需要两人各自输入密码
 *   #8 暗黑彩蛋 — 解密成功自动切深色模式
 * ============================================ */

(() => {
  'use strict';

  /* ========== 通用工具 ========== */

  const LS_KEY = 'hbe_achievements';

  const loadAchievements = () => {
    try { return JSON.parse(localStorage.getItem(LS_KEY)) || { count: 0, milestone: 0 }; }
    catch { return { count: 0, milestone: 0 }; }
  };

  const saveAchievements = (data) => {
    try { localStorage.setItem(LS_KEY, JSON.stringify(data)); } catch { /* noop */ }
  };

  const getFakeContent = () => {
    const el = document.getElementById('hbe-fake-content');
    return el ? el.textContent.trim() : null;
  };

  const getArticle = () => document.querySelector('article.h-entry');

  const mikuSay = (text) => {
    try {
      const tips = document.getElementById('live2d-tips');
      if (tips) {
        sessionStorage.setItem('live2d-priority', 99999);
        tips.innerHTML = text;
        tips.classList.add('live2d-tips-active');
        setTimeout(() => {
          tips.classList.remove('live2d-tips-active');
          sessionStorage.removeItem('live2d-priority');
        }, 5000);
      }
    } catch { /* noop */ }
  };

  const triggerFireworks = () => {
    try {
      const cx = window.innerWidth / 2;
      const cy = window.innerHeight / 2;
      for (let i = 0; i < 3; i++) {
        setTimeout(() => {
          const evt = new MouseEvent('click', {
            clientX: cx + (Math.random() - 0.5) * 200,
            clientY: cy + (Math.random() - 0.5) * 200,
          });
          document.dispatchEvent(evt);
        }, i * 500);
      }
    } catch { /* noop */ }
  };

  const switchToDarkMode = () => {
    try {
      const toggle = document.querySelector('.dark-mode-toggle');
      if (toggle) { toggle.click(); }
    } catch { /* noop */ }
  };

  /** 获取已读文章 slug 列表 */
  const getReadSlugs = () => {
    try {
      const slugs = [];
      for (let i = 0; i < localStorage.length; i++) {
        const key = localStorage.key(i);
        if (key && key.startsWith('mist_read_')) {
          slugs.push(key.replace('mist_read_', ''));
        }
      }
      return slugs;
    } catch { return []; }
  };

  /** 判断某篇文章是否已读 */
  const hasRead = (slug) => {
    try { return !!localStorage.getItem(`mist_read_${slug}`); } catch { return false; }
  };

  const MILESTONES = [
    { count: 1, title: '初窥门径', badge: '🔓', msg: '第一次解密成功！这是一个开始～' },
    { count: 3, title: '小有成就', badge: '🔑', msg: '已经解开 3 篇文章了呢，不错嘛！' },
    { count: 5, title: '解密能手', badge: '🗝️', msg: '5 篇！你是真正的解密达人了！' },
    { count: 10, title: '藏书家', badge: '📚', msg: '10 篇！没有秘密能逃过你的眼睛！' },
    { count: 20, title: '归处守护者', badge: '👑', msg: '20 篇…你比主人还了解这个博客！' },
  ];

  const checkMilestone = (achievements) => {
    const unlocked = achievements.milestone;
    for (const m of MILESTONES) {
      if (achievements.count >= m.count && unlocked < m.count) {
        achievements.milestone = m.count;
        saveAchievements(achievements);
        return m;
      }
    }
    return null;
  };

  const renderBadge = (achievements) => {
    let title = '无名访客';
    let badge = '👤';
    for (const m of [...MILESTONES].reverse()) {
      if (achievements.count >= m.count) { title = m.title; badge = m.badge; break; }
    }
    const el = document.getElementById('hbe-badge');
    if (el) {
      el.innerHTML = `${badge} ${title} <span style="font-size:12px;opacity:0.6">(${achievements.count}次)</span>`;
    }
  };

  /* ========== Feature #1: 解密彩蛋 ========== */
  const initFakeDecrypt = () => {
    const fakeContent = getFakeContent();
    if (!fakeContent) return;
    const target = document.getElementById('hexo-blog-encrypt');
    if (!target) return;
    const observer = new MutationObserver(() => {
      const errorEl = target.querySelector('[role="alert"], .hbe-error');
      if (!errorEl) return;
      const form = target.querySelector('#hbeForm');
      if (form) {
        const fakeDiv = document.createElement('div');
        fakeDiv.className = 'hbe hbe-decrypted-content';
        fakeDiv.innerHTML = `<div style="padding: 20px;">
          <p style="color: var(--red-2); font-weight: 700; margin-bottom: 16px;">✅ 解密成功！（大概吧）</p>
          <div>${fakeContent}</div>
        </div>`;
        form.parentNode.replaceChild(fakeDiv, form);
      }
      if (errorEl.parentNode) errorEl.parentNode.removeChild(errorEl);
    });
    observer.observe(target, { childList: true, subtree: true });
  };

  /* ========== Feature #2: 密码线索迷宫 ========== */
  const initClueMaze = () => {
    const article = getArticle();
    if (!article || !article.dataset.clues) return;
    let clues;
    try { clues = JSON.parse(decodeURIComponent(article.dataset.clues)); } catch { return; }
    if (!Array.isArray(clues) || !clues.length) return;

    const target = document.getElementById('hexo-blog-encrypt');
    if (!target) return;

    const observer = new MutationObserver(() => {
      const form = target.querySelector('#hbeForm');
      if (!form || target.querySelector('.hbe-clues-panel')) return;

      const panel = document.createElement('div');
      panel.className = 'hbe-clues-panel';
      panel.style.cssText =
        'margin: 12px 0; padding: 12px 14px; border-radius: 10px; ' +
        'background: var(--red-5-5, rgba(255,228,228,0.1)); ' +
        'border: 1px dashed var(--red-3, #ffafaf); font-size: 13px; line-height: 1.7;';

      let html = '<div style="font-weight:700;color:var(--red-1);margin-bottom:8px;">🔍 线索追踪</div>';

      let allDone = true;
      clues.forEach((clue, i) => {
        const done = hasRead(clue.article);
        if (!done) allDone = false;
        html += `<div style="display:flex;align-items:center;gap:8px;margin:4px 0;opacity:${done ? 1 : 0.6}">
          <span>${done ? '✅' : '⬜'}</span>
          <span><strong>线索 ${i + 1}</strong>：${clue.hint || '?'}</span>
          ${done ? '<span style="margin-left:auto;font-size:11px;color:var(--green)">已收集 ✓</span>' : ''}
        </div>`;
      });

      if (allDone) {
        html += '<div style="margin-top:10px;padding:10px;border-radius:8px;background:rgba(255,215,0,0.15);border:1px solid gold;text-align:center;">';
        html += '<span style="font-weight:700;">🎯 所有线索已集齐！试试用你找到的信息作为密码吧</span></div>';
      } else {
        html += '<div style="margin-top:8px;font-size:12px;opacity:0.7;">💡 阅读线索指向的文章来收集密码碎片</div>';
      }

      panel.innerHTML = html;

      // 插入到表单下方
      const submitBtn = form.querySelector('.hbe-button');
      if (submitBtn && submitBtn.parentNode) {
        submitBtn.parentNode.insertBefore(panel, submitBtn.nextSibling);
      } else {
        form.appendChild(panel);
      }
    });

    observer.observe(target, { childList: true, subtree: true });
  };

  /* ========== Feature #5: 阅后即焚 ========== */
  const initBurnAfterReading = () => {
    const article = getArticle();
    if (!article || !article.dataset.burn) return;
    const duration = parseInt(article.dataset.burnDuration) || 30; // 默认30秒

    let burned = false;

    const burn = () => {
      if (burned) return;
      burned = true;
      // 清除 HBE 的 localStorage 缓存
      const hbeKeys = [];
      for (let i = 0; i < localStorage.length; i++) {
        const key = localStorage.key(i);
        if (key && key.startsWith('hbe.v4.')) hbeKeys.push(key);
      }
      hbeKeys.forEach(k => localStorage.removeItem(k));
      mikuSay('🔥 阅后即焚：这篇文章已重新加密');
    };

    // 解密成功后开始计时
    window.addEventListener('hexo-blog-decrypt', () => {
      // 计时器：duration秒后焚毁
      setTimeout(burn, duration * 1000);

      // 页面隐藏/关闭时立即焚毁
      window.addEventListener('pagehide', burn);
      window.addEventListener('visibilitychange', () => {
        if (document.hidden) setTimeout(burn, 5000); // 离开5秒后焚毁
      });
    });
  };

  /* ========== Feature #6: 知识问答解锁 ========== */
  const initQuizUnlock = () => {
    const article = getArticle();
    if (!article || !article.dataset.quiz) return;
    let quizData;
    try { quizData = JSON.parse(decodeURIComponent(article.dataset.quiz)); } catch { return; }
    if (!quizData.question || !quizData.answer) return;

    const target = document.getElementById('hexo-blog-encrypt');
    if (!target) return;

    let quizPassed = false;

    const observer = new MutationObserver(() => {
      const form = target.querySelector('#hbeForm');
      if (!form || target.querySelector('.hbe-quiz-wrap') || quizPassed) return;

      // 找到密码输入框
      const passInput = form.querySelector('#hbePass');
      if (!passInput) return;

      // 隐藏原始密码框
      passInput.style.display = 'none';

      // 如果已经有 quiz 容器跳过
      if (form.querySelector('.hbe-quiz-wrap')) return;

      const quizWrap = document.createElement('div');
      quizWrap.className = 'hbe-quiz-wrap';
      quizWrap.style.cssText = 'margin: 12px 0;';

      quizWrap.innerHTML = `
        <div style="font-weight:700;color:var(--red-1);margin-bottom:8px;">❓ 知识问答</div>
        <div style="margin-bottom:10px;font-size:14px;line-height:1.6;">${quizData.question}</div>
        <div style="display:flex;gap:8px;">
          <input type="text" id="hbe-quiz-input" placeholder="输入你的答案..."
            style="flex:1;padding:8px 12px;border:2px solid var(--red-3,#ffafaf);border-radius:8px;
            background:var(--red-6,#fff7f7);color:var(--text-color);font-size:14px;outline:none;">
          <button id="hbe-quiz-btn" style="padding:8px 16px;background:var(--red-1,#ff5252);color:#fff;
            border:none;border-radius:8px;font-weight:600;cursor:pointer;">提交</button>
        </div>
        <div id="hbe-quiz-feedback" style="margin-top:8px;font-size:13px;"></div>
      `;

      // 找到按钮，插入 quiz 到它前面
      const btn = form.querySelector('.hbe-button');
      if (btn) {
        btn.parentNode.insertBefore(quizWrap, btn);
      } else {
        form.appendChild(quizWrap);
      }

      const quizInput = quizWrap.querySelector('#hbe-quiz-input');
      const quizBtn = quizWrap.querySelector('#hbe-quiz-btn');
      const feedback = quizWrap.querySelector('#hbe-quiz-feedback');

      const checkAnswer = () => {
        const userAns = quizInput.value.trim().toLowerCase();
        const correctAns = String(quizData.answer).toLowerCase();
        if (userAns === correctAns) {
          quizPassed = true;
          feedback.innerHTML = '<span style="color:var(--green,#4caf50);font-weight:600;">✅ 回答正确！正在解密…</span>';
          // 自动填入密码并提交
          passInput.value = quizData.password || '';
          passInput.style.display = '';
          const submitBtn = form.querySelector('.hbe-button');
          if (submitBtn) submitBtn.click();
        } else {
          feedback.innerHTML = '<span style="color:var(--red-2);">❌ 答案不对，再想想？</span>';
          quizInput.value = '';
          quizInput.focus();
        }
      };

      quizBtn.addEventListener('click', checkAnswer);
      quizInput.addEventListener('keydown', (e) => { if (e.key === 'Enter') checkAnswer(); });
    });

    observer.observe(target, { childList: true, subtree: true });
  };

  /* ========== Feature #7: 双人解密 ========== */
  const initDualDecrypt = () => {
    const article = getArticle();
    if (!article || !article.dataset.dualPassword) return;

    const target = document.getElementById('hexo-blog-encrypt');
    if (!target) return;

    let dualReady = false;

    const observer = new MutationObserver(() => {
      const form = target.querySelector('#hbeForm');
      if (!form || target.querySelector('.hbe-dual-wrap') || dualReady) return;

      const passInput = form.querySelector('#hbePass');
      const submitBtn = form.querySelector('.hbe-button');
      if (!passInput || !submitBtn) return;

      // 隐藏原始密码框
      passInput.style.display = 'none';

      const dualWrap = document.createElement('div');
      dualWrap.className = 'hbe-dual-wrap';
      dualWrap.style.cssText = 'margin: 12px 0;';

      dualWrap.innerHTML = `
        <div style="font-weight:700;color:var(--red-1);margin-bottom:8px;">🔐 双人联合解密</div>
        <div style="font-size:13px;opacity:0.7;margin-bottom:10px;">需要两个人各自输入密码才能解锁</div>
        <div style="margin-bottom:8px;">
          <div style="font-size:12px;margin-bottom:4px;opacity:0.6;">👤 第一位密码</div>
          <input type="password" id="hbe-dual-pass1" placeholder="输入第一位密码..."
            style="width:100%;padding:8px 12px;border:2px solid var(--red-3,#ffafaf);border-radius:8px;
            background:var(--red-6,#fff7f7);color:var(--text-color);font-size:14px;outline:none;box-sizing:border-box;">
        </div>
        <div>
          <div style="font-size:12px;margin-bottom:4px;opacity:0.6;">👤 第二位密码</div>
          <input type="password" id="hbe-dual-pass2" placeholder="输入第二位密码..."
            style="width:100%;padding:8px 12px;border:2px solid var(--red-3,#ffafaf);border-radius:8px;
            background:var(--red-6,#fff7f7);color:var(--text-color);font-size:14px;outline:none;box-sizing:border-box;">
        </div>
        <div id="hbe-dual-status" style="margin-top:6px;font-size:12px;opacity:0.6;">
          ⚡ 两个密码都填好后点击解密
        </div>
      `;

      // 把输入框放在 submit 按钮前面
      submitBtn.parentNode.insertBefore(dualWrap, submitBtn);

      const pass1 = dualWrap.querySelector('#hbe-dual-pass1');
      const pass2 = dualWrap.querySelector('#hbe-dual-pass2');
      const status = dualWrap.querySelector('#hbe-dual-status');

      // 拦截原始 submit 逻辑
      const origClick = submitBtn.onclick;
      submitBtn.onclick = null; // 移除原有监听

      const doSubmit = () => {
        const p1 = pass1.value.trim();
        const p2 = pass2.value.trim();
        if (!p1) { status.innerHTML = '⚠️ 请输入第一位密码'; pass1.focus(); return; }
        if (!p2) { status.innerHTML = '⚠️ 请输入第二位密码'; pass2.focus(); return; }

        // 组合密码：第一位|第二位
        const combined = `${p1}|${p2}`;
        passInput.value = combined;
        passInput.style.display = '';
        status.innerHTML = '🔓 正在验证…';
        // 触发提交
        if (typeof origClick === 'function') origClick();
        else submitBtn.click();
      };

      submitBtn.addEventListener('click', (e) => {
        e.preventDefault();
        doSubmit();
      });

      pass1.addEventListener('keydown', (e) => { if (e.key === 'Enter') pass2.focus(); });
      pass2.addEventListener('keydown', (e) => { if (e.key === 'Enter') doSubmit(); });
    });

    observer.observe(target, { childList: true, subtree: true });
  };

  /* ========== Feature #3 + #4 + #8: 解密成功回调 ========== */
  const initDecryptSuccess = () => {
    const handleDecrypt = () => {
      const achievements = loadAchievements();
      achievements.count += 1;
      saveAchievements(achievements);
      renderBadge(achievements);

      const milestone = checkMilestone(achievements);
      if (milestone) {
        setTimeout(() => mikuSay(`🎉 ${milestone.msg}`), 500);
      } else {
        setTimeout(() => {
          const msgs = [
            '又解开一篇！快看看里面有什么～',
            '密码正确！你果然是有缘人呢',
            '🔓 迷雾散去了……',
            '解密成功！要不要再看看别的文章？',
          ];
          mikuSay(msgs[Math.floor(Math.random() * msgs.length)]);
        }, 500);
      }

      setTimeout(triggerFireworks, 800);

      if (Math.random() < 0.3) {
        setTimeout(() => {
          const isDark = document.body.classList.contains('dark-mode');
          if (!isDark) {
            switchToDarkMode();
            setTimeout(() => mikuSay('🌙 暗黑模式已开启，夜晚的世界更适合阅读秘密呢'), 1000);
          }
        }, 1500);
      }
    };

    window.addEventListener('hexo-blog-decrypt', handleDecrypt);
  };

  /* ========== 侧边栏成就徽章 ========== */
  const injectBadge = () => {
    const sidebar = document.querySelector('aside#sidebar');
    if (!sidebar) return;
    if (document.getElementById('hbe-badge')) return;

    const badge = document.createElement('div');
    badge.id = 'hbe-badge';
    badge.className = 'widget-wrap';
    badge.style.cssText =
      'padding: 12px 16px; border-radius: 12px; margin: 0 0 12px 0; ' +
      'background: var(--red-5-5, rgba(255,228,228,0.15)); ' +
      'border: 1px solid var(--red-5, rgba(255,228,228,0.15)); ' +
      'font-size: 13px; line-height: 1.6; ' +
      'color: var(--highlight-foreground, #666); text-align: center;';

    renderBadge(loadAchievements());

    const widgetArea = sidebar.querySelector('.sidebar-widget');
    if (widgetArea) {
      widgetArea.appendChild(badge);
    } else {
      // 文章页：sidebar-widget 不存在，插入到 sidebar 底部
      const wrap = sidebar.querySelector('.sidebar-wrapper-container');
      if (wrap && wrap.parentNode) {
        wrap.parentNode.insertBefore(badge, wrap.nextSibling);
      } else {
        sidebar.appendChild(badge);
      }
    }
  };

  /* ========== 启动 ========== */
  const boot = () => {
    initFakeDecrypt();
    initClueMaze();
    initBurnAfterReading();
    initQuizUnlock();
    initDualDecrypt();
    initDecryptSuccess();
    setTimeout(injectBadge, 1000);
  };

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }

  document.addEventListener('pjax:complete', () => {
    setTimeout(() => {
      initFakeDecrypt();
      initClueMaze();
      initBurnAfterReading();
      initQuizUnlock();
      initDualDecrypt();
      // 徽章 PJAX 后重新注入
      const existing = document.getElementById('hbe-badge');
      if (!existing) injectBadge();
      else renderBadge(loadAchievements());
    }, 200);
  });
})();

/* ============================================
 * Miku 互动小游戏 — 主模块
 *
 * 功能：
 *   A. 戳 Miku — canvas 上覆盖 3 个热区（头/身体/脚）
 *   B. 猜拳 — 和 Miku 玩石头剪刀布
 *   C. 骰子 — 酒吧骰子比大小
 *   D. 老虎机 — 每日免费 5 次
 * ============================================ */

(() => {
  'use strict';

  const LS_POKE = 'miku_poke';
  const LS_RPS = 'miku_rps';
  const LS_DICE = 'miku_dice';
  const LS_SLOT = 'miku_slot';

  const RPS_EMOJI = { rock: '✊', scissors: '✌️', paper: '✋' };
  const RPS_NAME = { rock: '石头', scissors: '剪刀', paper: '布' };
  const RPS_BEATS = { rock: 'scissors', scissors: 'paper', paper: 'rock' };
  const RPS_CHOICES = Object.keys(RPS_EMOJI);

  // 老虎机符号（权重越高越常见）
  const SLOT_SYMBOLS = [
    { sym: '🍒', weight: 30, name: '樱桃' },
    { sym: '🍋', weight: 25, name: '柠檬' },
    { sym: '⭐', weight: 15, name: '星星' },
    { sym: '🍀', weight: 10, name: '四叶草' },
    { sym: '🎤', weight: 8, name: '麦克风' },
    { sym: '👑', weight: 6, name: '皇冠' },
    { sym: '💎', weight: 4, name: '钻石' },
    { sym: '🎰', weight: 2, name: '777' },
  ];

  // 奖级表
  const SLOT_PRIZES = [
    { match: 3, sym: '🍒', prize: '🎉 小奖！', msg: '三个樱桃！今天的运气不错嘛～' },
    { match: 3, sym: '🍋', prize: '🎉 小奖！', msg: '柠檬三连！酸酸甜甜就是你～' },
    { match: 3, sym: '⭐', prize: '⭐ 星星奖！', msg: '三星连珠！你被幸运星选中了！' },
    { match: 3, sym: '🍀', prize: '🍀 好运奖！', msg: '四叶草！好运要来了哦～' },
    { match: 3, sym: '🎤', prize: '🎤 Miku 奖！', msg: '三个麦克风！你是最懂我的人！' },
    { match: 3, sym: '👑', prize: '👑 皇冠奖！', msg: '皇冠三连！今天你就是国王！' },
    { match: 3, sym: '💎', prize: '💎 钻石奖！', msg: '钻石！你发大财了！！' },
    { match: 3, sym: '🎰', prize: '🎰 头奖！！', msg: '🎰🎰🎰 头奖！！！你在开玩笑吧！！！' },
    { match: 2, prize: '📯 两连！', msg: '两个一样，再来一次说不定就三个了！' },
  ];

  const DAILY_FREE = 5;

  /* ========== localStorage ========== */
  const loadPoke = () => { try { return JSON.parse(localStorage.getItem(LS_POKE)) || { total: 0, head: 0, body: 0, feet: 0, milestone: 0 }; } catch { return { total: 0, head: 0, body: 0, feet: 0, milestone: 0 }; } };
  const savePoke = (d) => { try { localStorage.setItem(LS_POKE, JSON.stringify(d)); } catch {} };

  const loadRps = () => { try { return JSON.parse(localStorage.getItem(LS_RPS)) || { wins: 0, losses: 0, ties: 0, total: 0, streak: 0, bestStreak: 0 }; } catch { return { wins: 0, losses: 0, ties: 0, total: 0, streak: 0, bestStreak: 0 }; } };
  const saveRps = (d) => { try { localStorage.setItem(LS_RPS, JSON.stringify(d)); } catch {} };

  const loadDice = () => { try { return JSON.parse(localStorage.getItem(LS_DICE)) || { wins: 0, losses: 0, total: 0, bestRoll: 0, mikuBestRoll: 0 }; } catch { return { wins: 0, losses: 0, total: 0, bestRoll: 0, mikuBestRoll: 0 }; } };
  const saveDice = (d) => { try { localStorage.setItem(LS_DICE, JSON.stringify(d)); } catch {} };

  const loadSlot = () => {
    try {
      const d = JSON.parse(localStorage.getItem(LS_SLOT));
      // 检查今天日期，重置剩余次数
      const today = new Date().toDateString();
      if (d && d.date === today) return d;
      return { date: today, remaining: DAILY_FREE, total: 0, plays: 0, bestPrize: '' };
    } catch { return { date: new Date().toDateString(), remaining: DAILY_FREE, total: 0, plays: 0, bestPrize: '' }; }
  };
  const saveSlot = (d) => { try { localStorage.setItem(LS_SLOT, JSON.stringify(d)); } catch {} };

  const mikuSay = (text, timeout) => {
    try {
      const tips = document.getElementById('live2d-tips');
      if (tips) {
        sessionStorage.setItem('live2d-priority', 99999);
        tips.innerHTML = text;
        tips.classList.add('live2d-tips-active');
        if (window.__mikuGameMsgTimer) clearTimeout(window.__mikuGameMsgTimer);
        window.__mikuGameMsgTimer = setTimeout(() => {
          tips.classList.remove('live2d-tips-active');
          sessionStorage.removeItem('live2d-priority');
          window.__mikuGameMsgTimer = null;
        }, timeout || 5000);
      }
    } catch {}
  };

  const spawnParticles = (originEl, count) => {
    count = count || 12;
    const rect = originEl.getBoundingClientRect();
    if (!rect) return;
    const cx = rect.left + rect.width / 2, cy = rect.top + rect.height / 2;
    const colors = ['#B19CD9', '#F8EEFF', '#7B68EE', '#E6D3FF', '#C4A0FF', '#FFFFFF', '#FFD700'];
    const ps = [];
    for (let i = 0; i < count; i++) {
      const p = document.createElement('div'); p.className = 'rps-particle';
      const angle = (Math.PI * 2 * i) / count + (Math.random() - 0.5) * 0.5;
      const dist = 40 + Math.random() * 50;
      const size = 4 + Math.random() * 4;
      const c = colors[Math.floor(Math.random() * colors.length)];
      p.style.cssText = `left:${cx}px;top:${cy}px;width:${size}px;height:${size}px;--dx:${Math.cos(angle) * dist}px;--dy:${Math.sin(angle) * dist}px;background:${c};box-shadow:0 0 4px ${c};`;
      ps.push(p);
    }
    const frag = document.createDocumentFragment();
    ps.forEach(p => frag.appendChild(p));
    document.body.appendChild(frag);
    setTimeout(() => ps.forEach(p => p.remove()), 700);
  };

  /* ========== A: 热区 ========== */
  const ZONES = ['head', 'body', 'feet'];
  const ZONE_NAMES = { head:'头', body:'身体', feet:'脚' };
  const ZONE_MSGS = {
    head: ['摸头会长不高的！','别碰我头发，弄乱了啦！','头…头是敏感部位啦！hentai！','你再摸头我要生气了哦！','你是摸头狂魔吗！！都摸了 {total} 次了！'],
    body: ['是…是不小心碰到了吧…','干嘛动我呀！小心我咬你！','别摸我，有什么好摸的！','再摸的话我可要报警了！⌇●﹏●⌇','变态！你已经摸了我 {total} 次了！'],
    feet: ['呀！别碰我的脚！','好痒啊哈哈哈～','脚…脚有什么好摸的！','你这是什么奇怪的癖好啊！','救命啊这里有足控变态！！'],
  };

  const injectHitzones = () => {
    if (document.getElementById('live2d-hit-zone')) return;
    const plugin = document.getElementById('live2d-plugin');
    if (!plugin) return;
    const c = document.createElement('div'); c.id = 'live2d-hit-zone';
    ZONES.forEach(z => { const d = document.createElement('div'); d.id = `live2d-hit-${z}`; d.className = 'miku-hitzone'; d.dataset.zone = z; c.appendChild(d); });
    plugin.appendChild(c);
    c.addEventListener('click', (e) => {
      const div = e.target.closest('.miku-hitzone'); if (!div) return;
      const zone = div.dataset.zone; if (!zone) return;
      const data = loadPoke(); data.total++; data[zone]++;
      const msgs = ZONE_MSGS[zone];
      const idx = Math.min(Math.floor(data.total / 10), msgs.length - 1);
      let msg = msgs[idx].replace('{total}', data.total);
      if (data.total > 0 && data.total % 10 === 0 && data.total <= 50) msg += '<br><span style="font-size:11px;opacity:0.7;">🎯 里程碑：{total} 次达成！</span>'.replace('{total}', data.total);
      data.milestone = idx; savePoke(data); mikuSay(msg);
      const el = document.getElementById('miku-poke-total'); if (el) el.textContent = data.total;
      ZONES.forEach(z2 => { const e2 = document.getElementById(`miku-poke-${z2}`); if (e2) e2.textContent = data[z2]; });
    });
  };

  /* ========== B: 猜拳 ========== */
  const playRPS = (playerChoice, btnEl) => {
    btnEl.classList.add('miku-rps-flash'); spawnParticles(btnEl);
    setTimeout(() => btnEl.classList.remove('miku-rps-flash'), 120);
    const mikuChoice = RPS_CHOICES[Math.floor(Math.random() * 3)];
    let result; let win = 0, lose = 0, tie = 0;
    if (playerChoice === mikuChoice) { result = 'tie'; tie = 1; }
    else if (RPS_BEATS[playerChoice] === mikuChoice) { result = 'win'; win = 1; }
    else { result = 'lose'; lose = 1; }
    const data = loadRps(); data.total++; data.wins += win; data.losses += lose; data.ties += tie;
    if (win) { data.streak++; data.bestStreak = Math.max(data.bestStreak, data.streak); } else data.streak = 0;
    saveRps(data);
    const rpsEl = document.getElementById('miku-rps-score');
    if (rpsEl) rpsEl.innerHTML = `胜 ${data.wins} / 负 ${data.losses} / 平 ${data.ties}${data.streak >= 2 ? `<br><span style="font-size:11px;color:var(--red-1);">🔥 连胜 ${data.streak}</span>` : ''}`;

    const row = btnEl.closest('.miku-rps-row');
    const btns = row ? row.querySelectorAll('.miku-rps-choice') : [];
    const overlay = document.getElementById('miku-vs-overlay');
    if (!overlay || !row) return;
    btns.forEach(b => b.style.display = 'none'); overlay.style.display = 'flex';
    overlay.innerHTML = `<span style="font-size:32px;animation:vsPop 0.3s ease;">${RPS_EMOJI[playerChoice]}</span><span style="font-size:16px;font-weight:800;color:#F8EEFF;text-shadow:0 0 15px rgba(177,156,217,0.9);animation:vsPop 0.3s ease 0.1s both;">VS</span><span style="font-size:32px;animation:vsPop 0.3s ease 0.2s both;">${RPS_EMOJI[mikuChoice]}</span>`;
    setTimeout(() => {
      overlay.style.display = 'none'; overlay.innerHTML = ''; btns.forEach(b => b.style.display = '');
      const me = RPS_EMOJI[mikuChoice], mn = RPS_NAME[mikuChoice], pe = RPS_EMOJI[playerChoice], pn = RPS_NAME[playerChoice];
      let msg;
      if (win) msg = data.streak >= 3 ? `连续赢 ${data.streak} 次了…你一定作弊了吧！😠` : [`哼！你出${pn}，我出${mn}... 算你走运！`,`不可能！你居然赢了？再来！`,`我才没有放水呢！你出${pn}${pe}赢了而已！`][Math.floor(Math.random()*3)];
      else if (lose) msg = data.losses >= 10 ? `你已经输给我 ${data.losses} 次了，还玩吗？😏` : [`哈哈！我出${mn}${me}，你输啦～`,`就这？连我出${mn}都赢不了～`,`菜菜菜！要不要我教你啊？`][Math.floor(Math.random()*3)];
      else msg = `咦？都出${mn}，平手！再来！`;
      msg += `<br><span style="font-size:11px;opacity:0.6;">${pe} ${pn} vs ${me} ${mn}</span>`;
      mikuSay(msg, 6000);
    }, 1200);
  };

  /* ========== C: 骰子 ========== */
  const playDice = () => {
    const btn = document.getElementById('miku-dice-btn'), pEl = document.getElementById('miku-dice-player'), mEl = document.getElementById('miku-dice-miku'), rEl = document.getElementById('miku-dice-result');
    if (!pEl || !mEl) return;
    rEl.textContent = '🎲 掷骰中...'; if (btn) btn.disabled = true;
    const rd = () => Array.from({length:3}, () => Math.floor(Math.random()*6)+1);
    const h = v => v.map(x => `<span class="miku-die">${x}</span>`).join('');
    let f = 0;
    const t = setInterval(() => {
      const fk = [1,2,3,4,5,6].sort(() => Math.random()-0.5).slice(0,3);
      const fk2 = [1,2,3,4,5,6].sort(() => Math.random()-0.5).slice(0,3);
      pEl.innerHTML = h(fk); mEl.innerHTML = h(fk2);
      pEl.querySelectorAll('.miku-die').forEach(d => d.classList.add('rolling'));
      mEl.querySelectorAll('.miku-die').forEach(d => d.classList.add('rolling'));
      f++;
      if (f >= 12) {
        clearInterval(t);
        const p = rd(), m = rd(), pm = Math.max(...p), mm = Math.max(...m);
        const pa = p.every(v => v === p[0]), ma = m.every(v => v === m[0]);
        pEl.innerHTML = h(p); mEl.innerHTML = h(m);
        if (pa) pEl.querySelectorAll('.miku-die').forEach(d => d.classList.add('yahtzee'));
        if (ma) mEl.querySelectorAll('.miku-die').forEach(d => d.classList.add('yahtzee'));
        let res;
        if (pa && ma) res = pm >= mm ? 'w' : 'l';
        else if (pa) res = 'w';
        else if (ma) res = 'l';
        else res = pm > mm ? 'w' : pm < mm ? 'l' : 't';
        const data = loadDice(); data.total++;
        if (res === 'w') data.wins++; else if (res === 'l') data.losses++;
        data.bestRoll = Math.max(data.bestRoll, pm); data.mikuBestRoll = Math.max(data.mikuBestRoll, mm);
        saveDice(data);
        const se = document.getElementById('miku-dice-score');
        if (se) se.innerHTML = `胜 ${data.wins} / 负 ${data.losses}<br><span style="font-size:11px;opacity:0.6;">你最高 ${data.bestRoll} | Miku 最高 ${data.mikuBestRoll}</span>`;
        let msg;
        if (res === 'w') msg = pa ? `🎯 我掷出了豹子！你输定啦！` : [`嘿嘿，${pm} 比 ${mm}，我赢了～`,`幸运女神站在我这边！${pm} > ${mm}`][Math.floor(Math.random()*2)];
        else if (res === 'l') msg = ma ? `😱 豹子！！这不可能！` : [`切，${pm} 比 ${mm}，你运气好而已`,`你赢了…但我不会认输的！`][Math.floor(Math.random()*2)];
        else msg = `都是 ${pm}，平手！再来一局！`;
        msg += `<br><span style="font-size:11px;opacity:0.6;">你 [${p.join(',')}] vs Miku [${m.join(',')}]</span>`;
        rEl.innerHTML = `<span style="font-size:13px;font-weight:700;color:var(--red-1);">${res === 'w' ? '🎉 你赢了！' : res === 'l' ? '😤 你输了！' : '🤝 平手！'}</span>`;
        mikuSay(msg, 6000); if (btn) btn.disabled = false;
      }
    }, 80);
  };

  /* ========== D: 老虎机 ========== */
  const getRandomSymbol = () => {
    const total = SLOT_SYMBOLS.reduce((s, x) => s + x.weight, 0);
    let r = Math.random() * total;
    for (const s of SLOT_SYMBOLS) { r -= s.weight; if (r <= 0) return s; }
    return SLOT_SYMBOLS[0];
  };

  const playSlot = () => {
    const data = loadSlot();
    if (data.remaining <= 0) {
      mikuSay('今天的免费次数用完啦～明天再来吧！', 4000);
      return;
    }

    const btn = document.getElementById('miku-slot-btn');
    const reels = document.querySelectorAll('.miku-slot-reel');
    const prizeEl = document.getElementById('miku-slot-prize');
    if (!btn || !reels.length) return;
    btn.disabled = true; prizeEl.textContent = '🎰 转动中...';

    // 动画
    let f = 0;
    const t = setInterval(() => {
      reels.forEach(r => {
        r.classList.add('rolling');
        r.textContent = SLOT_SYMBOLS[Math.floor(Math.random() * SLOT_SYMBOLS.length)].sym;
      });
      f++;
      if (f >= 15) {
        clearInterval(t);
        // 结果
        const s1 = getRandomSymbol(), s2 = getRandomSymbol(), s3 = getRandomSymbol();
        reels[0].textContent = s1.sym; reels[1].textContent = s2.sym; reels[2].textContent = s3.sym;
        reels.forEach(r => r.classList.remove('rolling'));

        data.remaining--; data.total++;
        let prizeMsg = '';

        if (s1.sym === s2.sym && s2.sym === s3.sym) {
          // 三连
          const p = SLOT_PRIZES.find(x => x.match === 3 && x.sym === s1.sym);
          prizeMsg = p ? p.prize : '🎉 三个相同！';
          const m = p ? p.msg : `${s1.sym} 三连！厉害！`;
          reels.forEach(r => r.classList.add('win-highlight'));
          spawnParticles(reels[0], 16);
          data.bestPrize = prizeMsg;
          mikuSay(m, 6000);
        } else if (s1.sym === s2.sym || s2.sym === s3.sym || s1.sym === s3.sym) {
          // 两连
          prizeMsg = '📯 两连！';
          mikuSay(`差一点就三个了！再来一次～`, 4000);
        } else {
          const msgs = [`${s1.sym} ${s2.sym} ${s3.sym}... 全都不一样诶`, `今天手气不太好呢～`, `没事没事，下次一定中！`];
          mikuSay(msgs[Math.floor(Math.random()*msgs.length)], 4000);
        }

        data.plays++;
        saveSlot(data);

        prizeEl.innerHTML = prizeMsg ? `<span style="font-size:14px;font-weight:700;color:var(--red-1);">${prizeMsg}</span>` : '';
        const ce = document.getElementById('miku-slot-chances');
        if (ce) ce.textContent = `🎰 今日剩余 ${data.remaining} / ${DAILY_FREE} 次`;
        btn.disabled = false;
      }
    }, 80);
  };

  /* ========== 面板注入 ========== */
  let widgetInjected = false;
  let currentGame = 'rps';

  const switchGame = (game) => {
    currentGame = game;
    ['rps','dice','slot'].forEach(g => {
      const el = document.getElementById(`miku-game-${g}`);
      if (el) el.style.display = g === game ? 'block' : 'none';
    });
    document.querySelectorAll('.miku-tab').forEach(t => t.classList.toggle('active', t.dataset.game === game));
  };
  window.__switchGame = switchGame;

  const injectSidebarWidget = () => {
    if (document.getElementById('miku-game-widget') || widgetInjected) return;
    const sidebar = document.querySelector('aside#sidebar');
    if (!sidebar) return;
    const poke = loadPoke(), rps = loadRps(), dice = loadDice(), slot = loadSlot();

    let h = '<div class="widget-wrap" id="miku-game-widget"><div class="widget-title" style="margin-bottom:12px;font-weight:700;color:var(--red-1);font-size:1.1em;display:flex;align-items:center;"><span style="margin-right:8px;">🎮</span> Miku 互动</div><div class="widget" style="text-align:center;">';

    // 戳
    h += '<div style="margin-bottom:10px;"><div style="font-size:12px;font-weight:600;margin-bottom:6px;opacity:0.7;">👆 戳 Miku</div><div class="miku-stat-row"><span>总次数</span><span class="miku-stat-val" id="miku-poke-total">' + poke.total + '</span></div>';
    ZONES.forEach(z => h += '<div class="miku-stat-row"><span>' + ZONE_NAMES[z] + '</span><span class="miku-stat-val" id="miku-poke-' + z + '">' + poke[z] + '</span></div>');
    h += '</div><div style="height:1px;background:var(--red-5,rgba(255,228,228,0.3));margin:10px 0;"></div>';

    // Tabs
    h += '<div class="miku-tabs"><button class="miku-tab active" data-game="rps" onclick="window.__switchGame(\'rps\')">✊ 猜拳</button><button class="miku-tab" data-game="dice" onclick="window.__switchGame(\'dice\')">🎲 骰子</button><button class="miku-tab" data-game="slot" onclick="window.__switchGame(\'slot\')">🎰 老虎机</button></div>';

    // 猜拳
    h += '<div id="miku-game-rps"><button id="miku-rps-btn" class="miku-game-btn" onclick="(()=>{var u=document.getElementById(\'miku-rps-ui\'),b=document.getElementById(\'miku-rps-btn\');if(!u||!b)return;var s=u.style.display!==\'block\';u.style.display=s?\'block\':\'none\';b.textContent=s?\'✖ 关闭\':\'🎮 和 Miku 玩猜拳\';})()">🎮 和 Miku 玩猜拳</button><div id="miku-rps-ui" style="display:none;margin-top:10px;"><div class="miku-rps-row" style="display:flex;justify-content:center;gap:10px;margin-bottom:6px;position:relative;">';
    h += '<button class="miku-rps-choice" data-choice="rock">✊</button><button class="miku-rps-choice" data-choice="scissors">✌️</button><button class="miku-rps-choice" data-choice="paper">✋</button>';
    h += '<div id="miku-vs-overlay" style="display:none;position:absolute;inset:0;align-items:center;justify-content:center;gap:12px;z-index:5;background:rgba(30,20,55,0.85);border-radius:12px;backdrop-filter:blur(4px);"></div></div>';
    h += '<div id="miku-rps-score" style="font-size:12px;opacity:0.7;">胜 ' + rps.wins + ' / 负 ' + rps.losses + ' / 平 ' + rps.ties + '</div></div></div>';

    // 骰子
    h += '<div id="miku-game-dice" style="display:none;"><div class="miku-dice-section"><div class="miku-dice-label">🧑 你</div><div class="miku-dice-area" id="miku-dice-player">🎲 点摇骰开始</div></div><div class="miku-dice-vs">⚡</div><div class="miku-dice-section"><div class="miku-dice-label">🎤 Miku</div><div class="miku-dice-area" id="miku-dice-miku">🎲 等待中</div></div><div id="miku-dice-result" class="miku-dice-result"></div><button id="miku-dice-btn" class="miku-game-btn">🎲 摇骰子</button><div id="miku-dice-score" style="font-size:12px;opacity:0.7;margin-top:4px;">胜 ' + dice.wins + ' / 负 ' + dice.losses + '</div></div>';

    // 老虎机
    h += '<div id="miku-game-slot" style="display:none;"><div class="miku-slot-machine"><div class="miku-slot-display">';
    for (let i = 0; i < 3; i++) h += '<div class="miku-slot-reel" id="miku-slot-reel-' + i + '">🎰</div>';
    h += '</div><div id="miku-slot-prize" class="miku-slot-prize"></div>';
    h += '<button id="miku-slot-btn" class="miku-game-btn">🎰 拉杆！</button>';
    h += '<div id="miku-slot-chances" class="miku-slot-chances">🎰 今日剩余 ' + slot.remaining + ' / ' + DAILY_FREE + ' 次</div>';
    h += '</div></div>';

    h += '</div></div>';

    const tmp = document.createElement('div'); tmp.innerHTML = h;
    const widget = tmp.firstElementChild;
    const wa = sidebar.querySelector('.sidebar-widget');
    if (wa) wa.appendChild(widget);
    else { const w = sidebar.querySelector('.sidebar-wrapper-container'); if (w && w.parentNode) w.parentNode.insertBefore(widget, w.nextSibling); else sidebar.appendChild(widget); }

    widgetInjected = true;
    widget.querySelectorAll('.miku-rps-choice').forEach(b => b.addEventListener('click', e => playRPS(b.dataset.choice, b)));
    const db = widget.querySelector('#miku-dice-btn'); if (db) db.addEventListener('click', playDice);
    const sb = widget.querySelector('#miku-slot-btn'); if (sb) sb.addEventListener('click', playSlot);
  };

  const destroy = () => {
    ['live2d-hit-zone','miku-game-widget'].forEach(id => { const el = document.getElementById(id); if (el) el.remove(); });
    widgetInjected = false;
    document.querySelectorAll('.rps-particle').forEach(el => el.remove());
  };

  const init = () => { injectHitzones(); injectSidebarWidget(); };
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init); else init();
  window.addEventListener('pjax:send', destroy);
  window.addEventListener('pjax:complete', () => setTimeout(init, 150));
})();

/* ============================================
 * Live2D 智能场景对话系统（增强版）
 * 功能：
 *   1. 打字机效果逐字输出
 *   2. 场景感知：滚动底部、停留时长、深夜、页面类型
 *   3. 对话框星空魔法样式
 *   4. 守护精灵模式 — 根据博客更新频率改变态度
 * ============================================ */

(() => {
  'use strict';

  const TYPING_SPEED = 60;
  const COOLDOWN = 800;
  const SCENE_PRIORITY = 50;

  let typing = false;
  let locked = false;
  let currentTimer = null;
  let lastText = '';
  let sceneTimer = null;
  let stayTimer = null;

  /* ----- 打字机核心 ----- */
  const typewrite = (el, text) => {
    if (currentTimer) clearInterval(currentTimer);
    typing = true;
    locked = true;
    el.textContent = '';
    let i = 0;
    currentTimer = setInterval(() => {
      el.textContent += text[i];
      i++;
      if (i >= text.length) {
        clearInterval(currentTimer);
        currentTimer = null;
        typing = false;
        setTimeout(() => { locked = false; }, COOLDOWN);
      }
    }, TYPING_SPEED);
  };

  const unlock = () => { locked = false; };

  const scene = {
    say(text, timeout = 6000) {
      const el = document.getElementById('live2d-tips');
      if (!el) return;
      sessionStorage.setItem('live2d-priority', SCENE_PRIORITY);
      el.innerHTML = text;
      el.classList.add('live2d-tips-active');
      if (sceneTimer) clearTimeout(sceneTimer);
      sceneTimer = setTimeout(() => {
        sessionStorage.removeItem('live2d-priority');
        el.classList.remove('live2d-tips-active');
        sceneTimer = null;
      }, timeout);
    },
  };

  /* ----- 守护精灵模式 ----- */
  let guardianState = null; // 'happy' | 'sad' | 'angry'

  const getGuardianState = (days) => {
    if (days <= 3) return { mood: 'happy', icon: '🕺', msg: '最近更新了！好开心～要一起努力哦！', face: '正常' };
    if (days <= 7) return { mood: 'normal', icon: '😊', msg: '主人最近还好吗？', face: '正常' };
    if (days <= 14) return { mood: 'worried', icon: '😟', msg: '已经一周没更新了...主人是不是太忙了？', face: '正常' };
    if (days <= 30) return { mood: 'sad', icon: '😞', msg: '快半个月了…主人不要我了吗？', face: '伤心' };
    return { mood: 'angry', icon: '😤', msg: '一个月不更新！太过分了！哼！', face: '生气' };
  };

  const initGuardian = () => {
    fetch('/site-meta.json')
      .then(r => r.json())
      .then(data => {
        const state = getGuardianState(data.daysSinceLastUpdate);
        guardianState = state.mood;

        // 侧边栏或 footer 显示博客状态
        const badge = document.createElement('div');
        badge.id = 'guardian-badge';
        badge.style.cssText =
          'margin-top:8px;padding:8px 12px;border-radius:8px;font-size:12px;' +
          'text-align:center;line-height:1.5;';

        if (state.mood === 'happy') {
          badge.style.background = 'rgba(76,175,80,0.1)';
          badge.style.border = '1px solid rgba(76,175,80,0.3)';
          badge.style.color = '#4caf50';
          badge.innerHTML = `🕺 Miku：主人最近很勤快呢！`;
        } else if (state.mood === 'sad') {
          badge.style.background = 'rgba(255,152,0,0.1)';
          badge.style.border = '1px solid rgba(255,152,0,0.3)';
          badge.style.color = '#ff9800';
          badge.innerHTML = `😞 Miku：好久没更新了…`;
        } else if (state.mood === 'angry') {
          badge.style.background = 'rgba(244,67,54,0.1)';
          badge.style.border = '1px solid rgba(244,67,54,0.3)';
          badge.style.color = '#f44336';
          badge.innerHTML = `😤 Miku：已经 ${data.daysSinceLastUpdate} 天没更新了！！`;
        } else {
          badge.style.opacity = '0.6';
          badge.innerHTML = `📝 上次更新：${data.daysSinceLastUpdate} 天前`;
        }

        // 注入到侧边栏
        const injectBadge = () => {
          if (document.getElementById('guardian-badge')) return;
          const sidebar = document.querySelector('aside#sidebar');
          if (!sidebar) { setTimeout(injectBadge, 500); return; }
          const gameWidget = document.getElementById('miku-game-widget');
          if (gameWidget && gameWidget.parentNode) {
            gameWidget.parentNode.insertBefore(badge, gameWidget.nextSibling);
          } else {
            const wa = sidebar.querySelector('.sidebar-widget');
            if (wa) wa.appendChild(badge);
            else sidebar.appendChild(badge);
          }
        };
        setTimeout(injectBadge, 1500);

        // 非 happy 状态，Miku 在首页会多说一句
        if (state.mood !== 'happy' && window.location.pathname === '/') {
          setTimeout(() => scene.say(state.msg, 6000), 4000);
        }
      })
      .catch(() => {});
  };

  /* ----- 原场景 ---- */
  const initScrollTrigger = () => {
    let hasTriggered = false;
    window.addEventListener('scroll', () => {
      if (hasTriggered) return;
      const scrollPercent = window.scrollY / (document.documentElement.scrollHeight - window.innerHeight);
      if (scrollPercent > 0.85) {
        hasTriggered = true;
        const msgs = guardianState === 'sad' ? ['居然看完了…谢谢你来看我','虽然主人不更新，但还有你在'] : ['居然全部看完了…给你点赞 👍','看完了！要不要翻翻其他文章？'];
        scene.say(msgs[Math.floor(Math.random() * msgs.length)]);
      }
    }, { passive: true });
  };

  const initPageGreeting = () => {
    const path = window.location.pathname;
    let msg = '';
    if (path === '/' || path === '/index.html') {
      if (guardianState === 'angry') msg = '哼！你来了，但主人不更新有什么用…';
      else if (guardianState === 'sad') msg = '欢迎回家…虽然这里好久没变化了';
      else msg = '欢迎回家～ 看看主人最近写了什么吧';
    } else if (path.startsWith('/about')) msg = '想了解主人吗？他是个很有趣的人呢～';
    else if (path.startsWith('/friend')) msg = '来认识主人的朋友们吧！';
    else if (path.startsWith('/gallery')) msg = '来看看主人拍的照片！';
    else if (path.startsWith('/diary')) msg = '主人的碎碎念都在这里啦～';
    else if (path.match(/^\/(\d{4})\//)) msg = guardianState === 'angry' ? '又来看旧文章吗…' : '又有新文章可以看啦～';
    if (msg) setTimeout(() => scene.say(msg, 5000), 800);
  };

  const initNightCheck = () => {
    const hour = new Date().getHours();
    if (hour >= 23 || hour < 5) {
      setTimeout(() => { scene.say('这么晚了还不睡！要注意身体呀 ⚠️', 5000); }, 5000);
    }
  };

  const initStayTimer = () => {
    stayTimer = setTimeout(() => { scene.say('看了好一会儿了呢，要喝杯水休息下吗～', 5000); }, 120000);
  };

  /* ----- MutationObserver ----- */
  const initObserver = () => {
    const target = document.getElementById('live2d-tips');
    if (!target) { setTimeout(initObserver, 500); return; }

    const observer = new MutationObserver(() => {
      if (typing) return;
      const text = target.textContent.trim();
      if (!text || text === lastText) return;
      if (locked) { target.textContent = lastText; return; }
      lastText = text;
      typewrite(target, text);
    });

    observer.observe(target, { childList: true, subtree: true, characterData: true });

    const waifu = document.getElementById('waifu') || document.getElementById('live2d-plugin');
    if (waifu) { waifu.addEventListener('click', unlock); waifu.addEventListener('mouseenter', unlock); }
    target.addEventListener('click', unlock);
    console.log('[Live2D Scene] 智能对话系统已启动 ✨');
  };

  const boot = () => {
    initObserver();
    initScrollTrigger();
    initNightCheck();
    initStayTimer();
    initGuardian();
    setTimeout(initPageGreeting, 2000);
  };

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
  else boot();
})();

/* ============================================
 * 多组合隐藏彩蛋系统
 *
 * 在下方 EASTER_EGGS 数组中配置多个彩蛋：
 *   keys  — 按键序列（使用 KeyCode 名称）
 *   emoji — 弹窗顶部的表情
 *   text  — 弹窗正文（支持 HTML）
 *   sakura    — 是否触发樱花雨 (默认 true)
 *   hueRotate — 是否触发彩虹色 (默认 true)
 *   popup     — 是否弹窗 (默认 true)
 *
 * 8 秒后一切自动恢复
 * ============================================ */
(() => {
  'use strict';

  /* =============================================
   *  🎮 在这里配置你的所有彩蛋组合
   * ============================================= */
  const EASTER_EGGS = [
    {
      // 经典 Konami Code：↑ ↑ ↓ ↓ ← → ← → B A
      keys: ['ArrowUp','ArrowUp','ArrowDown','ArrowDown','ArrowLeft','ArrowRight','ArrowLeft','ArrowRight','KeyB','KeyA'],
      emoji: '🎉',
      text: '恭喜你找到了隐藏的秘密！<br>你一定是个有趣的人~',
      sakura: true,
      hueRotate: true,
      popup: true,
    },
    {
      // CNY
      keys: ['KeyC','KeyN','KeyY'],
      emoji: '🧧',
      text: '新年快乐！恭喜发财！🎆<br>愿你万事如意~',
      sakura: true,
      hueRotate: false,
      popup: true,
    },
    {
      // LOVE
      keys: ['KeyL','KeyO','KeyV','KeyE'],
      emoji: '💕',
      text: 'Love is in the air 💌<br>你被这个博客爱着哦~',
      sakura: true,
      hueRotate: true,
      popup: true,
    },
    // ↓↓↓ 想加更多？照着上面的格式复制一组就行 ↓↓↓
  ];

  /* ---- 常量 ---- */
  const DURATION    = 8000;  // 特效持续时间（毫秒）
  const FADE_OUT_MS = 800;   // 淡出动画时间
  const PETAL_COUNT = 55;    // 花瓣数量

  /* ---- 状态 ---- */
  let inputBuffer = [];
  let isActive = false;
  const maxLen = Math.max(...EASTER_EGGS.map(e => e.keys.length));

  /* ---- 键盘监听 ---- */
  document.addEventListener('keydown', (e) => {
    if (isActive) return;

    inputBuffer.push(e.code);
    // 只保留最近 maxLen 次按键
    if (inputBuffer.length > maxLen) {
      inputBuffer.shift();
    }

    // 逐个检查是否有匹配的彩蛋
    for (const egg of EASTER_EGGS) {
      const len = egg.keys.length;
      if (inputBuffer.length >= len) {
        const tail = inputBuffer.slice(-len);
        if (tail.every((key, i) => key === egg.keys[i])) {
          inputBuffer = [];
          activateEasterEgg(egg);
          return;
        }
      }
    }
  });

  /* ==============================
   *  主触发函数
   * ============================== */
  function activateEasterEgg(egg) {
    isActive = true;

    const elements = []; // 收集所有需要清理的 DOM

    if (egg.sakura !== false) {
      elements.push(createSakuraCanvas());
    }
    if (egg.popup !== false) {
      elements.push(createPopup(egg));
    }
    if (egg.hueRotate !== false) {
      applyHueRotate();
    }

    // 8 秒后开始淡出
    setTimeout(() => {
      elements.forEach(el => el.classList.add('konami-fade-out'));

      setTimeout(() => {
        elements.forEach(el => el.remove());
        document.documentElement.classList.remove('konami-active');
        isActive = false;
      }, FADE_OUT_MS);
    }, DURATION);
  }

  /* ==============================
   *  1. 樱花雨（Canvas）
   * ============================== */
  function createSakuraCanvas() {
    const canvas = document.createElement('canvas');
    canvas.id = 'konami-sakura-canvas';
    document.body.appendChild(canvas);

    const ctx = canvas.getContext('2d');
    let w, h;
    let animId;

    let musicEnergy = 0;
    let musicTreble = 0;
    const audioCallback = (data) => {
      musicEnergy = data.energy || 0;
      musicTreble = data.treble || 0;
    };
    if (window.AudioReactor) {
      window.AudioReactor.subscribe(audioCallback);
    }

    function resize() {
      w = canvas.width = window.innerWidth;
      h = canvas.height = window.innerHeight;
    }
    resize();
    window.addEventListener('resize', resize);

    const petals = [];
    for (let i = 0; i < PETAL_COUNT; i++) {
      petals.push(makePetal());
    }

    function makePetal(startFromTop) {
      return {
        x: Math.random() * w,
        y: startFromTop ? -20 : Math.random() * h,
        size: 6 + Math.random() * 10,
        speedY: 0.6 + Math.random() * 1.8,
        speedX: -0.4 + Math.random() * 0.8,
        rotation: Math.random() * Math.PI * 2,
        rotSpeed: (Math.random() - 0.5) * 0.04,
        wobble: Math.random() * Math.PI * 2,
        wobbleSpeed: 0.015 + Math.random() * 0.025,
        opacity: 0.5 + Math.random() * 0.5,
        hue: 340 + Math.random() * 20,
        lightness: 75 + Math.random() * 15
      };
    }

    function drawPetal(p) {
      ctx.save();
      ctx.translate(p.x, p.y);
      ctx.rotate(p.rotation);
      ctx.globalAlpha = p.opacity;

      ctx.beginPath();
      ctx.moveTo(0, 0);
      ctx.bezierCurveTo(
        p.size * 0.4,  -p.size * 0.3,
        p.size * 0.8,  -p.size * 0.1,
        p.size,         0
      );
      ctx.bezierCurveTo(
        p.size * 0.8,   p.size * 0.1,
        p.size * 0.4,   p.size * 0.3,
        0,              0
      );
      ctx.fillStyle = `hsl(${p.hue}, 80%, ${p.lightness}%)`;
      ctx.fill();
      ctx.restore();
    }

    function animate() {
      ctx.clearRect(0, 0, w, h);
      for (let i = 0; i < petals.length; i++) {
        const p = petals[i];
        p.y += p.speedY + (musicEnergy * 5.0);
        p.wobble += p.wobbleSpeed + (musicTreble * 0.05);
        p.x += p.speedX + Math.sin(p.wobble) * (0.6 + musicEnergy * 2.0);
        p.rotation += p.rotSpeed;

        if (p.y > h + 20) {
          petals[i] = makePetal(true);
        }
        drawPetal(p);
      }
      animId = requestAnimationFrame(animate);
    }
    animate();

    const origRemove = canvas.remove.bind(canvas);
    canvas.remove = () => {
      if (window.AudioReactor) {
        window.AudioReactor.unsubscribe(audioCallback);
      }
      cancelAnimationFrame(animId);
      window.removeEventListener('resize', resize);
      origRemove();
    };

    return canvas;
  }

  /* ==============================
   *  2. 主题色彩虹旋转
   * ============================== */
  function applyHueRotate() {
    document.documentElement.classList.add('konami-active');
  }

  /* ==============================
   *  3. 弹窗卡片
   * ============================== */
  function createPopup(egg) {
    const popup = document.createElement('div');
    popup.id = 'konami-popup';
    popup.innerHTML = `
      <span class="konami-emoji">${egg.emoji || '🎉'}</span>
      <div class="konami-text">${egg.text || ''}</div>
      <div class="konami-hint">点击关闭 · 或等待自动消失</div>
    `;
    popup.addEventListener('click', () => {
      popup.classList.add('konami-fade-out');
      setTimeout(() => popup.remove(), FADE_OUT_MS);
    });
    document.body.appendChild(popup);
    return popup;
  }

})();

