    const [prefs, setPrefsState] = React.useState(() => Object.assign({}, DEFAULT_PREFS, readJSON(PREFS_KEY)));
    const [queueOpen, setQueueOpen] = React.useState(false);
    const [consoleOpen, setConsoleOpen] = React.useState(false);
    const [zoom, setZoom] = React.useState(0);

    const currentTrack = tracks[player.currentIndex] || tracks[0] || DEFAULT_TRACK;
    const defaultMeta = (meta && meta.defaults) || {};
    const trackMeta = Object.assign({}, defaultMeta, (meta && meta.tracks || []).find(t =>
      String(t.neteaseId || t.id || t.title) === String(currentTrack.sourceId || currentTrack.id) || (t.title && t.title === currentTrack.title)) || {});
    const page = Object.assign({ title: root.dataset.title || 'Music Space', eyebrow: 'Now Playing' }, meta && meta.page || {});
    const mood = (meta && meta.page && meta.page.mood) || '';

    useAlbumColors(currentTrack, appRef);

    React.useEffect(() => {
      let cancelled = false;
      fetch(root.dataset.metaUrl || '/music/music-meta.json').then(r => r.ok ? r.json() : null).then(json => { if (!cancelled && json) setMeta(json); }).catch(() => {});
      return () => { cancelled = true; };
    }, [root]);

    React.useEffect(() => {
      const el = appRef.current; if (!el) return;
      el.style.setProperty('--ms-glow', String(prefs.glow));
      const preset = COLOR_PRESETS.find(c => c.key === prefs.lyricColor);
      el.style.setProperty('--ms-lyric-color', preset && preset.color ? preset.color : 'var(--album-auto, #f3e7cf)');
      // mirror lyric style into the 3D field
      const ctrl = universeRef.current;
      if (ctrl && ctrl.setLyricStyle) {
        const cs = getComputedStyle(el);
        const col = (preset && preset.color) || cs.getPropertyValue('--album-auto').trim() || '#f3e7cf';
        ctrl.setLyricStyle(col, prefs.glow);
      }
    }, [prefs.glow, prefs.lyricColor, currentTrack.id]);

    // feed the universe: album colors + cover planet (read the eased CSS vars)
    React.useEffect(() => {
      const el = appRef.current, ctrl = universeRef.current;
      if (!el || !ctrl) return;
      const cs = getComputedStyle(el);
      const a = cs.getPropertyValue('--album-primary').trim();
      const b = cs.getPropertyValue('--album-secondary').trim();
      if (a) ctrl.setAlbumColors(a, b || a);
      if (ctrl.setCover) ctrl.setCover(currentTrack.cover || '', a);
    }, [currentTrack.id, currentTrack.cover, meta]);

    React.useEffect(() => {
      const ctrl = universeRef.current;
      if (ctrl) ctrl.setPlaying(player.status === 'playing');
    }, [player.status]);

    // Web Audio: attach the APlayer <audio> once it exists (a user gesture resumes the ctx)
    React.useEffect(() => {
      const ctrl = universeRef.current;
      if (ctrl && ctrl.attachAudio && ap && ap.audio) ctrl.attachAudio(ap.audio);
    }, [ap, player.status]);

    // escape closes panels
    React.useEffect(() => {
      const onKey = (e) => { if (e.key === 'Escape') { setQueueOpen(false); setConsoleOpen(false); } };
      window.addEventListener('keydown', onKey);
      return () => window.removeEventListener('keydown', onKey);
    }, []);

    const setLocal = patch => setLocalState(prev => { const next = Object.assign({}, prev, patch); writeJSON(STORAGE_KEY, next); return next; });
    const setPref = patch => setPrefsState(prev => { const next = Object.assign({}, prev, patch); writeJSON(PREFS_KEY, next); return next; });

    const isPlaying = player.status === 'playing';
    const panelOpen = queueOpen || consoleOpen;

    return h('div', { ref: appRef, className: cx('music-space', isPlaying ? 'is-playing' : 'is-paused', prefs.beat && 'ms-beat', reduced && 'is-reduced', panelOpen && 'has-panel', prefs.starfield && 'has-universe') },
      h(UniverseCanvas, {
        enabled: prefs.starfield, reduced,
        controllerRef: universeRef, interactionRef: stageRef,
        onReady: (ctrl) => {
          const el = appRef.current;
          if (el) { const cs = getComputedStyle(el); ctrl.setAlbumColors(cs.getPropertyValue('--album-primary').trim(), cs.getPropertyValue('--album-secondary').trim()); }
          ctrl.setPlaying(player.status === 'playing');
          if (ctrl.setCover) ctrl.setCover(currentTrack.cover || '', (el && getComputedStyle(el).getPropertyValue('--album-primary').trim()));
          if (ctrl.onLyricHover) ctrl.onLyricHover((on) => { if (stageRef.current) stageRef.current.classList.toggle('is-lyric-hover', on); });
          if (ap && ap.audio && ctrl.attachAudio) ctrl.attachAudio(ap.audio);
        },
        onZoom: (z) => setZoom(z)
      }),
      h(Ambient),

      h('section', { className: 'ms-stage', ref: stageRef },
        h(TopBar, { page, status: player.status, mood }),
        h(LyricStage, { track: currentTrack, player, universeRef, hasUniverse: prefs.starfield }),
        h('div', { className: 'ms-dock' },
          prefs.coverflow && h(CoverFlow, { tracks, currentIndex: player.currentIndex, api, vinyl: prefs.vinyl, isPlaying }),
          h(Transport, { track: currentTrack, player, api, local, setLocal,
            onQueue: () => { setQueueOpen(o => !o); setConsoleOpen(false); },
            onConsole: () => { setConsoleOpen(o => !o); setQueueOpen(false); },
            queueOpen, consoleOpen })
        )
      ),

      // edge hover zones (desktop reveal)
      h('div', { className: 'ms-edge ms-edge--left', onMouseEnter: () => setQueueOpen(true) }, h('span', { className: 'ms-edge__hint' }, '歌单')),
      h('div', { className: 'ms-edge ms-edge--right', onMouseEnter: () => setConsoleOpen(true) }, h('span', { className: 'ms-edge__hint' }, '视觉')),

      panelOpen && h('div', { className: 'ms-scrim', onClick: () => { setQueueOpen(false); setConsoleOpen(false); } }),
      h('div', { className: cx('ms-panel-wrap ms-panel-wrap--left', queueOpen && 'is-open'), onMouseLeave: () => setQueueOpen(false) },
        h(QueuePanel, { tracks, currentIndex: player.currentIndex, api, ap, onClose: () => setQueueOpen(false) })
      ),
      h('div', { className: cx('ms-panel-wrap ms-panel-wrap--right', consoleOpen && 'is-open'), onMouseLeave: () => setConsoleOpen(false) },
        h(ConsolePanel, { prefs, setPref, onClose: () => setConsoleOpen(false) })
      )
    );
  }

  function initMusicSpace() {
    const root = document.getElementById('music-space-root');
    if (!root || root.dataset.mounted === 'true') return;
    if (!window.React || !window.ReactDOM) { window.setTimeout(initMusicSpace, 120); return; }
    root.dataset.mounted = 'true';
    document.body.classList.add('has-music-space');
    const reactRoot = ReactDOM.createRoot(root);
    root.__musicSpaceRoot = reactRoot;
    reactRoot.render(h(MusicSpaceApp, { root }));
  }

  function destroyMusicSpace() {
    const root = document.getElementById('music-space-root');
    document.body.classList.remove('has-music-space');
    if (root && root.__musicSpaceRoot) {
      root.__musicSpaceRoot.unmount();
      delete root.__musicSpaceRoot;
      delete root.dataset.mounted;
    }
  }

  window.initMusicSpace = initMusicSpace;
  window.destroyMusicSpace = destroyMusicSpace;

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', initMusicSpace);
  else initMusicSpace();
  document.addEventListener('pjax:complete', initMusicSpace);
  document.addEventListener('pjax:send', destroyMusicSpace);
})();

/* ============================================
 * 文章迷雾解锁系统 — 客户端脚本
 *
 * 迷雾锁类型：
 *   1. 时间锁 (unlock_date) — 到达指定日期才能看
 *   2. 进度锁 (read_required) — 读完 N 篇文章才能看
 *   3. 禁阅锁 (forbid_start / forbid_end) — 指定时间段内不能看
 *
 * 使用方式 (文章 front-matter):
 *   unlock_date: 2030-06-01          # 在此日期后才能看
 *   forbid_start: 2025-05-05         # 在此日期后不能看
 *   forbid_end: 2025-06-01           # 在此日期后才能看
 *   或者精确到分钟：
 *   forbid_start: 2026-01-01 16:30
 *   forbid_end: 2026-03-15 15:00
 *   read_required: 3                # 读满 N 篇才能看
 *   mist_title: "迷雾的标题"         # 自定义迷雾标题
 * ============================================ */

(() => {
  'use strict';

  /* ---- 工具函数 ---- */
  const getArticleEl = () => document.querySelector(
    'article[data-unlock-date], article[data-read-required], article[data-forbid-start], article[data-forbid-end]'
  );

  const getReadCount = () => {
    try { return parseInt(localStorage.getItem('mist_read_count') || '0', 10); }
    catch { return 0; }
  };

  const setReadCount = (n) => {
    try { localStorage.setItem('mist_read_count', String(n)); } catch { /* noop */ }
  };

  const markArticleRead = (slug) => {
    try {
      const key = `mist_read_${slug}`;
      if (localStorage.getItem(key)) return;
      localStorage.setItem(key, '1');
      setReadCount(getReadCount() + 1);
    } catch { /* noop */ }
  };

  /** 解析日期字符串：支持 "2026-01-01" 或 "2026-01-01 16:30" 或 ISO 格式 */
  const parseDate = (str) => {
    if (!str) return null;
    const dt = str.trim();
    // Hexo 可能输出 ISO 格式如 "2030-12-31T16:00:00.000Z" → 直接传 Date 构造
    if (dt.includes('T') || dt.includes('Z')) {
      const d = new Date(dt);
      return isNaN(d.getTime()) ? null : d;
    }
    // "2026-01-01 16:30" 格式
    if (/^\d{4}-\d{2}-\d{2}\s+\d{1,2}:\d{2}$/.test(dt)) {
      return new Date(dt.replace(' ', 'T') + ':00');
    }
    // "2026-01-01" 格式 — 视为当天的 00:00
    return new Date(dt + 'T00:00:00');
  };

  /* 获取迷雾状态 */
  const getMistState = (el) => {
    const now = new Date();
    const unlockDate = parseDate(el.dataset.unlockDate);
    const forbidStart = parseDate(el.dataset.forbidStart);
    const forbidEnd = parseDate(el.dataset.forbidEnd);
    const readRequired = parseInt(el.dataset.readRequired || '0', 10);

    // 禁阅锁：
    //   forbid_start 单独使用 → 此日期之后永久禁阅
    //   forbid_start + forbid_end → 此时间段内禁阅
    let inForbid = false;
    let forbidTarget = null;
    if (forbidStart && forbidEnd) {
      // 时间段禁阅：start <= now < end
      inForbid = now >= forbidStart && now < forbidEnd;
      if (inForbid) forbidTarget = forbidEnd;
    } else if (forbidStart && !forbidEnd) {
      // 永久禁阅：now >= start
      inForbid = now >= forbidStart;
      forbidTarget = null; // 无倒计时
    }

    const timeLocked = unlockDate && now < unlockDate;
    const progressLocked = readRequired > 0 && getReadCount() < readRequired;

    return {
      locked: inForbid || timeLocked || progressLocked,
      inForbid,
      forbidTarget,
      timeLocked,
      progressLocked,
      unlockDate,
      forbidStart,
      forbidEnd,
      readRequired,
      readCount: getReadCount(),
    };
  };

  /* 计算剩余时间 */
  const getTimeRemaining = (target) => {
    const diff = target - new Date();
    if (diff <= 0) return { days: 0, hours: 0, minutes: 0, seconds: 0, total: 0 };
    return {
      days: Math.floor(diff / (1000 * 60 * 60 * 24)),
      hours: Math.floor((diff / (1000 * 60 * 60)) % 24),
      minutes: Math.floor((diff / (1000 * 60)) % 60),
      seconds: Math.floor((diff / 1000) % 60),
      total: diff,
    };
  };

  /* 格式化日期显示 */
  const formatDate = (d) => {
    if (!d) return '';
    return `${d.getFullYear()}.${String(d.getMonth()+1).padStart(2,'0')}.${String(d.getDate()).padStart(2,'0')}`;
  };

  const formatDateTime = (d) => {
    if (!d) return '';
    const h = String(d.getHours()).padStart(2, '0');
    const m = String(d.getMinutes()).padStart(2, '0');
    return `${formatDate(d)} ${h}:${m}`;
  };

  /* 渲染迷雾遮罩 HTML */
  const renderOverlay = (state) => {
    const overlay = document.createElement('div');
    overlay.className = 'mist-overlay';

    let html = '<div class="mist-icon">🔮</div>';

    const title = document.querySelector('article')?.dataset.mistTitle || '被迷雾笼罩的文章';
    html += `<div class="mist-title">${title}</div>`;

    if (state.inForbid) {
      html += `<div class="mist-subtitle">⛔ 这篇文章在当前时间不可访问</div>`;
      if (state.forbidTarget) {
        // 有时间范围 → 显示倒计时
        html += `<div class="mist-countdown" id="mist-forbid-timer">
          ⛔ 不可访问期还剩<br>
          <span class="cd-num" id="cd-days">--</span> 天
          <span class="cd-num" id="cd-hours">--</span> 时
          <span class="cd-num" id="cd-minutes">--</span> 分
          <span class="cd-num" id="cd-seconds">--</span> 秒
        </div>`;
      } else {
        // 永久禁阅 → 无倒计时
        html += `<div class="mist-countdown">⛔ 这篇文章已被永久封印</div>`;
      }
    }

    if (state.timeLocked) {
      const dateStr = formatDateTime(state.unlockDate);
      html += `<div class="mist-subtitle">这篇被时间迷雾封印了<br>将在 ${dateStr} 揭晓</div>`;
      html += `<div class="mist-countdown" id="mist-countdown-timer">
        ⏳ <span class="cd-num" id="cd-days">--</span> 天
        <span class="cd-num" id="cd-hours">--</span> 时
        <span class="cd-num" id="cd-minutes">--</span> 分
        <span class="cd-num" id="cd-seconds">--</span> 秒
      </div>`;
    }

    if (state.progressLocked) {
      const pct = Math.min(100, Math.round((state.readCount / state.readRequired) * 100));
      html += '<div class="mist-subtitle">📖 需要阅读足够多的文章才能揭开迷雾</div>';
      html += `<div class="mist-progress">
        <span>已读 <strong>${state.readCount}</strong> / ${state.readRequired}</span>
        <div class="mist-progress-bar">
          <div class="mist-progress-fill" style="width:${pct}%"></div>
        </div>
      </div>`;
      const remain = state.readRequired - state.readCount;
      if (remain > 0) {
        html += `<div class="mist-countdown">📖 再读 <strong>${remain}</strong> 篇即可解锁</div>`;
      }
    }

    overlay.innerHTML = html;
    return overlay;
  };

  /* 更新倒计时 */
  const updateCountdown = (target, prefix) => {
    const r = getTimeRemaining(target);
    const id = (name) => `${prefix}-${name}`;
    const daysEl = document.getElementById(id('days'));
    if (!daysEl) return r.total > 0;
    daysEl.textContent = String(r.days).padStart(2, '0');
    document.getElementById(id('hours')).textContent = String(r.hours).padStart(2, '0');
    document.getElementById(id('minutes')).textContent = String(r.minutes).padStart(2, '0');
    document.getElementById(id('seconds')).textContent = String(r.seconds).padStart(2, '0');
    return r.total > 0;
  };

  /* ---- 监视器 ---- */
  const watchCountdown = (el, state) => {
    if (!state.locked) return;

    const target = state.inForbid ? state.forbidTarget : state.unlockDate;
    if (!target) return;

    // 初始化显示 (ID 固定为 cd-days/cd-hours/cd-minutes/cd-seconds)
    updateCountdown(target, 'cd');

    const timer = setInterval(() => {
      // 重新获取完整状态（因为可能跨过了 forbid 窗口）
      const fresh = getMistState(el);
      if (!fresh.locked) {
        el.classList.add('mist-unlocked');
        clearInterval(timer);
        return;
      }
      const t = fresh.inForbid ? fresh.forbidTarget : fresh.unlockDate;
      updateCountdown(t, 'cd');
    }, 1000);
  };

  const watchProgress = (el, state) => {
    if (!state.progressLocked) return;
    const timer = setInterval(() => {
      const cur = getReadCount();
      if (cur >= state.readRequired) {
        el.classList.add('mist-unlocked');
        clearInterval(timer);
      }
    }, 2000);
  };

  /* ---- 初始化 ---- */
  const init = () => {
    const el = getArticleEl();
    if (!el) return;

    const state = getMistState(el);

    // 没有锁 → 解锁并记录已读
    if (!state.locked) {
      el.classList.add('mist-unlocked');
      const slug = el.id?.replace(/^post-/, '');
      if (slug) markArticleRead(slug);
      return;
    }

    // 挂载迷雾遮罩
    const articleInner = el.querySelector('.article-inner');
    if (!articleInner) return;
    if (articleInner.querySelector('.mist-overlay')) return; // 防止 PJAX 重复
    const overlay = renderOverlay(state);
    articleInner.style.position = 'relative';
    articleInner.appendChild(overlay);

    const slug = el.id?.replace(/^post-/, '');
    if (slug && !state.progressLocked) markArticleRead(slug);

    // 启动监视器
    watchCountdown(el, state);
    watchProgress(el, state);
  };

  /* ---- 启动 ---- */
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

  document.addEventListener('pjax:complete', () => setTimeout(init, 100));
})();

/* ============================================================
   Music Universe — a 3D lyric cosmos (Three.js, no build step)
   Starfield · galaxy spiral · nebula · dust · meteors ·
   god-ray core · orbit-drag inertia · scroll dolly ·
   pointer parallax · album-color ambience · gentle breathing
   Exposes: window.MusicUniverse.create(canvas, opts)
   ============================================================ */
(function () {
  'use strict';
  if (window.MusicUniverse) return;

  function clamp(n, a, b) { return Math.max(a, Math.min(b, n)); }
  function lerp(a, b, t) { return a + (b - a) * t; }

  function create(canvas, opts) {
    opts = opts || {};
    var THREE = window.THREE;
    if (!THREE || !canvas) return null;

    var interactionEl = opts.interactionEl || canvas;
    var reduced = !!opts.reduced;
    var isMobile = window.matchMedia && window.matchMedia('(max-width: 720px)').matches;
    var DPR = Math.min(window.devicePixelRatio || 1, isMobile ? 1.4 : 2);

    // ---- renderer ----
    var renderer;
    try {
      renderer = new THREE.WebGLRenderer({ canvas: canvas, antialias: !isMobile, alpha: true, powerPreference: 'high-performance' });
    } catch (e) { return null; }
    renderer.setPixelRatio(DPR);
    renderer.setClearColor(0x000000, 0);

    var scene = new THREE.Scene();
    var camera = new THREE.PerspectiveCamera(58, 1, 0.1, 2000);
    camera.position.set(0, 0, 120);

    // universe rig — orbit rotates this group; camera dollies on z
    var universe = new THREE.Group();
    scene.add(universe);

    // depth sub-groups for parallax
    var farGroup = new THREE.Group();   // galaxy + nebula (slow)
    var midGroup = new THREE.Group();   // stars (mid)
    var nearGroup = new THREE.Group();  // dust (fast)
    universe.add(farGroup, midGroup, nearGroup);

    // ---- shared color uniforms (album ambience) ----
    var uColorA = { value: new THREE.Color('#9ed8ff') };
    var uColorB = { value: new THREE.Color('#cbacff') };
    var targetA = new THREE.Color('#9ed8ff');
    var targetB = new THREE.Color('#cbacff');
    var uTime = { value: 0 };
    var uEnergy = { value: 0 };      // gentle 0..1 breathing while playing
    var uHover = { value: 0 };       // 0..1 hover intensifier
    var uBass = { value: 0 };        // low freq   → particle jitter
    var uMid = { value: 0 };         // mid freq   → bloom breathing
    var uTreble = { value: 0 };      // high freq  → star twinkle
    var uStarBright = { value: 0.7 };// 星空亮度 (star alpha multiplier)
    var uStarCut = { value: 0 };     // 星空密度阈值 (discard aRandom > cut)
    // scalar knobs (not shader uniforms): reactivity/depth/cinematic
    var vparam = { react: 0.85, depth: 1, cine: 0.5 };

    var COUNTS = isMobile
      ? { stars: 1400, galaxy: 2600, dust: 220 }
      : { stars: 3000, galaxy: 5200, dust: 480 };

    // ============================================================
    //  STARFIELD — instanced points, soft, twinkling, tinted
    // ============================================================
    function buildStars() {
      var n = COUNTS.stars;
      var pos = new Float32Array(n * 3);
      var siz = new Float32Array(n);
      var pha = new Float32Array(n);
      var tnt = new Float32Array(n);
      var rnd = new Float32Array(n);
      for (var i = 0; i < n; i++) {
        // spherical shell with depth spread
        var r = 200 + Math.pow(Math.random(), 0.6) * 640;
        var th = Math.random() * Math.PI * 2;
        var ph = Math.acos(2 * Math.random() - 1);
        pos[i * 3] = r * Math.sin(ph) * Math.cos(th);
        pos[i * 3 + 1] = r * Math.cos(ph) * 0.62;              // flatten vertically a touch
        pos[i * 3 + 2] = r * Math.sin(ph) * Math.sin(th);
        siz[i] = 0.6 + Math.pow(Math.random(), 2.2) * 3.4;
        pha[i] = Math.random() * Math.PI * 2;
        tnt[i] = Math.random() < 0.16 ? Math.random() : 0;      // few colored, most white
        rnd[i] = Math.random();                                 // for density culling
      }
      var g = new THREE.BufferGeometry();
      g.setAttribute('position', new THREE.BufferAttribute(pos, 3));
      g.setAttribute('aSize', new THREE.BufferAttribute(siz, 1));
      g.setAttribute('aPhase', new THREE.BufferAttribute(pha, 1));
      g.setAttribute('aTint', new THREE.BufferAttribute(tnt, 1));
      g.setAttribute('aRandom', new THREE.BufferAttribute(rnd, 1));
      var m = new THREE.ShaderMaterial({
        uniforms: { uTime: uTime, uColorA: uColorA, uColorB: uColorB, uEnergy: uEnergy, uHover: uHover, uTreble: uTreble, uBass: uBass, uStarBright: uStarBright, uStarCut: uStarCut, uPixelRatio: { value: DPR } },
        transparent: true, depthWrite: false, blending: THREE.AdditiveBlending,
        vertexShader: [
          'attribute float aSize; attribute float aPhase; attribute float aTint; attribute float aRandom;',
          'uniform float uTime; uniform float uEnergy; uniform float uHover; uniform float uTreble; uniform float uBass; uniform float uStarCut; uniform float uPixelRatio;',
          'varying float vTint; varying float vTw;',
          'void main(){',
          '  vTint = aTint;',
          '  if(aRandom < uStarCut){ gl_Position = vec4(2.0,2.0,2.0,1.0); gl_PointSize = 0.0; return; }', // density cull
          '  vec3 p = position;',
          '  p += normalize(p + 0.001) * uBass * 2.2 * sin(uTime*3.0 + aPhase);',  // low freq: subtle radial jitter
          '  vec4 mv = modelViewMatrix * vec4(p,1.0);',
          '  float tw = 0.6 + 0.4*sin(uTime*1.4 + aPhase);',           // twinkle (high-freq shimmer)
          '  tw = mix(tw, 1.0, uEnergy*0.4);',
          '  tw += uTreble * 0.5 * (0.5 + 0.5*sin(uTime*9.0 + aPhase*3.0));',      // high freq: star sparkle
          '  vTw = tw;',
          '  float s = aSize * (300.0/-mv.z) * uPixelRatio * (1.0 + uHover*0.18 + uTreble*0.25);',
          '  gl_PointSize = clamp(s, 0.5, 9.0);',
          '  gl_Position = projectionMatrix * mv;',
          '}'
        ].join('\n'),
        fragmentShader: [
          'uniform vec3 uColorA; uniform vec3 uColorB; uniform float uStarBright;',
          'varying float vTint; varying float vTw;',
          'void main(){',
          '  vec2 c = gl_PointCoord - 0.5;',
          '  float d = length(c);',
          '  float a = smoothstep(0.5, 0.0, d);',                       // soft round
          '  a *= a;',
          '  vec3 col = mix(vec3(1.0), mix(uColorA,uColorB,vTint), vTint*0.9);',
          '  gl_FragColor = vec4(col, a * vTw * (0.5 + uStarBright));',  // brightness knob (0.5 baseline lift)
          '}'
        ].join('\n')
      });
      var pts = new THREE.Points(g, m);
      pts.frustumCulled = false;
      midGroup.add(pts);
      return { g: g, m: m, pts: pts };
    }

    // ============================================================
    //  GALAXY — logarithmic spiral arms, warm core → cool rim
    // ============================================================
    function buildGalaxy() {
      var n = COUNTS.galaxy, arms = 3;
      var pos = new Float32Array(n * 3);
      var siz = new Float32Array(n);
      var mix = new Float32Array(n);   // 0 core .. 1 rim
      var pha = new Float32Array(n);
      for (var i = 0; i < n; i++) {
        var t = Math.pow(Math.random(), 0.5);
        var radius = 60 + t * 560;
        var arm = i % arms;
        var ang = radius * 0.011 + arm * (Math.PI * 2 / arms);
        var spread = (1 - t) * 30 + 14;
        var rx = (Math.random() - 0.5) * spread;
        var ry = (Math.random() - 0.5) * spread * 0.42;   // thin disk
        var rz = (Math.random() - 0.5) * spread;
        pos[i * 3] = Math.cos(ang) * radius + rx;
        pos[i * 3 + 1] = ry - 60;                          // sit galaxy slightly below/behind
        pos[i * 3 + 2] = Math.sin(ang) * radius + rz - 240;
        siz[i] = 0.5 + Math.random() * 2.2;
        mix[i] = t;
        pha[i] = Math.random() * 6.28;
      }
      var g = new THREE.BufferGeometry();
      g.setAttribute('position', new THREE.BufferAttribute(pos, 3));
      g.setAttribute('aSize', new THREE.BufferAttribute(siz, 1));
      g.setAttribute('aMix', new THREE.BufferAttribute(mix, 1));
      g.setAttribute('aPhase', new THREE.BufferAttribute(pha, 1));
      var m = new THREE.ShaderMaterial({
        uniforms: { uTime: uTime, uColorA: uColorA, uColorB: uColorB, uEnergy: uEnergy, uPixelRatio: { value: DPR } },
        transparent: true, depthWrite: false, blending: THREE.AdditiveBlending,
        vertexShader: [
          'attribute float aSize; attribute float aMix; attribute float aPhase;',
          'uniform float uTime; uniform float uEnergy; uniform float uPixelRatio;',
          'varying float vMix; varying float vTw;',
          'void main(){',
          '  vMix = aMix;',
          '  vec4 mv = modelViewMatrix * vec4(position,1.0);',
          '  vTw = 0.7 + 0.3*sin(uTime*0.8 + aPhase);',
          '  float s = aSize * (300.0/-mv.z) * uPixelRatio;',
          '  gl_PointSize = clamp(s, 0.4, 6.0);',
          '  gl_Position = projectionMatrix * mv;',
          '}'
        ].join('\n'),
        fragmentShader: [
          'uniform vec3 uColorA; uniform vec3 uColorB; uniform float uEnergy;',
          'varying float vMix; varying float vTw;',
          'void main(){',
