      if (hay.indexOf(q) === -1) return false;
    }
    return true;
  }

  function itemYear(i) {
    if (i.watched_date) {
      var m = String(i.watched_date).match(/^(\d{4})/);
      if (m) return +m[1];
    }
    return i.year || 0;
  }

  function groupByYear(items) {
    var groups = Object.create(null);
    items.forEach(function (i) {
